import{_ as e,o as t,c as a,R as o}from"./chunks/framework.9uzLHhAa.js";const k=JSON.parse('{"title":"实战篇","description":"","frontmatter":{},"headers":[],"relativePath":"fe/test/Combat.md","filePath":"fe/test/Combat.md","lastUpdated":1696600456000}'),r={name:"fe/test/Combat.md"},n=o('<h1 id="实战篇" tabindex="-1">实战篇 <a class="header-anchor" href="#实战篇" aria-label="Permalink to &quot;实战篇&quot;">​</a></h1><p>still work on this.</p><p>测试的最终目标是<strong>提升代码信心</strong> 。实现这个目标的关键要素是：<strong>避免测试代码实现细节，要像真实用户那样去使用业务代码</strong>。所以特别是在做集成测试的时候，切勿掉进代码的各种case里面，测试的用例更应该贴近用户的行为， 因为当你的用例越接近用户使用的样子，你从测试获得的代码的信心就越高。也就是说，对给定的待测对象，我们希望测试它对外呈现的功能，而非内部的结构与实现细节，即使用<a href="https://zh.wikipedia.org/wiki/%E9%BB%91%E7%9B%92%E6%B5%8B%E8%AF%95" target="_blank" rel="noreferrer">黑盒测试</a></p><blockquote><p>The more your tests resemble the way your software is used, the more confidence they can give you. - Kent C. Dodds</p></blockquote><h2 id="redux" tabindex="-1">redux <a class="header-anchor" href="#redux" aria-label="Permalink to &quot;redux&quot;">​</a></h2><h2 id="react-router-v6" tabindex="-1">React Router v6 <a class="header-anchor" href="#react-router-v6" aria-label="Permalink to &quot;React Router v6&quot;">​</a></h2><h2 id="react-hooks" tabindex="-1">react hooks <a class="header-anchor" href="#react-hooks" aria-label="Permalink to &quot;react hooks&quot;">​</a></h2><p>当写公共library的自定义hooks，需要对hooks进行单元测试，使用这个<a href="https://react-hooks-testing-library.com/" target="_blank" rel="noreferrer">react-hooks-testing-library</a> 可以对hooks进行单独的测试，不用放在组件里，不然就会报错：</p><blockquote><p>Invariant Violation: Hooks can only be called inside the body of a function component.</p></blockquote><p>对于<code>React 18</code>，<code>renderHook</code>这个Api已经可以在<code>react-testing-library</code> (<a href="https://github.com/testing-library/react-testing-library/pull/991" target="_blank" rel="noreferrer">PR</a>) 和 <code>react-native-testing-library</code> 导入使用了。</p><blockquote><p>使用原则: ：当你的hook不与组件强相关，拥有独立含义时可以使用；当你的hook只被一个组件使用，且和它的定义强相关时，则不建议使用。</p></blockquote><h2 id="i18next" tabindex="-1">i18next <a class="header-anchor" href="#i18next" aria-label="Permalink to &quot;i18next&quot;">​</a></h2>',12),i=[n];function s(c,l,h,d,u,b){return t(),a("div",null,i)}const _=e(r,[["render",s]]);export{k as __pageData,_ as default};
